Here's a sample code for implementing Dijkstra's algorithm in C++:

```
#include <iostream>
#include <vector>
#include <queue>
#include <climits>

using namespace std;

typedef pair<int, int> pii;

vector<pair<int, int>> adjList[100005];
int dist[100005];

void dijkstra(int src, int n) {
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    pq.push({0, src});
    dist[src] = 0;

    while(!pq.empty()) {
        int u = pq.top().second;
        pq.pop();

        for(auto neighbor : adjList[u]) {
            int v = neighbor.first;
            int w = neighbor.second;

            if(dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
}

int main() {
    int n, m, src;
    cin >> n >> m >> src;
    for(int i = 1; i <= n; i++) {
        dist[i] = INT_MAX;
    }
    for(int i = 0; i < m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        adjList[u].push_back({v, w});
        adjList[v].push_back({u, w});
    }

    dijkstra(src, n);

    for(int i = 1; i <= n; i++) {
        if(dist[i] == INT_MAX) {
            cout << "INF ";
        } else {
            cout << dist[i] << " ";
        }
    }
    cout << endl;
}
```
In this sample code, `adjList` is the adjacency list of the graph, `dist` is an array that keeps track of the minimum distance from the source to each vertex, and `src` is the source vertex. 

First, we initialize `dist` to infinity for all vertices except the source. We use a priority queue to select the next vertex with the smallest distance from the source. For each neighbor of the selected vertex, we update the distance if the current distance plus the weight of the edge is smaller than the distance recorded for the neighbor. We also add the neighbor to the priority queue so we can continue exploring the graph.

Finally, we output the distance to each vertex from the source. If the distance is still `INT_MAX`, we output "INF" to indicate that there is no path from the source to that vertex.

